+namespace sv_75efa851450a42c0b7e096d948928197.Services;
+
+/// <summary>
+/// Scoped service that holds the current low-stock alert count and
+/// notifies all subscribed components when the count changes.
+/// Scoped lifetime = one instance per circuit = per-user isolation.
+/// </summary>
+public class InventoryAlertState
+{
+    public int LowStockCount { get; private set; }
+
+    /// <summary>
+    /// Subscribers must wrap their handler in InvokeAsync when the
+    /// update originates from a background thread (timer).
+    /// </summary>
+    public event Action? OnChange;
+
+    public void SetCount(int count)
+    {
+        LowStockCount = count;
+        OnChange?.Invoke();
+    }
+}
+

