@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@inject InventoryAlertState AlertState
@implements IDisposable
@using sv_75efa851450a42c0b7e096d948928197.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<p>
    Currently viewing: <strong>@Warehouse?.Name</strong>
</p>

<div class="card mb-4" style="max-width: 20rem;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text display-4">
            @AlertState.LowStockCount
        </p>
        <p class="text-muted">Items below minimum stock level. Refreshes every 10 s.</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        // Subscribe so this component also re-renders when the shared
        // state is updated (same event the AlertBadge subscribes to).
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _alertHandler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // (Re)start polling whenever the warehouse changes.
        await StopPollingAsync();
        await PollOnceAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = Task.Run(async () =>
        {
            try
            {
                while (await _timer.WaitForNextTickAsync(_cts.Token))
                {
                    await PollOnceAsync();
                }
            }
            catch (OperationCanceledException) { }
        });
    }

    private async Task PollOnceAsync()
    {
        var warehouseId = Warehouse?.Id ?? WarehouseInfo.Default.Id;
        var count = await AlertService.GetLowStockCountAsync(warehouseId);

        // Updating the scoped state fires OnChange, which notifies
        // ALL subscribers (this page AND the sidebar AlertBadge).
        AlertState.SetCount(count);
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        AlertState.OnChange -= _alertHandler;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

